.category-card {
    border: 1px solid #ccc;
    padding: 10px;
    margin: 10px 0;
    display: flex;
    justify-content: space-between;
    align-items: center;
}
.category-card.exceeded-limit {
    text-decoration: line-through;
    color: red;
}

