dashboard.content:
function renderCategories() {
    const categoriesSection = document.getElementById('categories');
    categoriesSection.innerHTML = '';
    budgetCategories.forEach(category => {
        const card = document.createElement('div');
        card.className = `category-card ${category.balance > category.limit ? 'exceeded-limit' : ''}`;
        card.innerHTML = `
            <div>
                <h3>${category.name}</h3>
                <p>Balance: $${category.balance}</p>
                <p>Limit: $${category.limit}</p>
            </div>
            <button onclick="editCategory('${category.name}')">Edit</button>
        `;
        categoriesSection.appendChild(card);
    });
}

function renderSummary() {
    const summary = document.getElementById('summary');
    summary.innerHTML = `
        <p>Total Income: $${totalIncome}</p>
        <p>Total Expenses: $${totalExpenses}</p>
    `;
}

