update_category_balance.content:
function editCategory(name) {
    const category = budgetCategories.find(c => c.name === name);
    const form = document.createElement('form');
    form.innerHTML = `
        <input type="number" id="new-balance" placeholder="New Balance">
        <button type="submit">Update Balance</button>
    `;
    document.body.appendChild(form);

    form.addEventListener('submit', (e) => {
        e.preventDefault();
        const newBalance = parseFloat(document.getElementById('new-balance').value);
        category.balance = newBalance;
        renderCategories();
        document.body.removeChild(form);
    });
}

